// Helper functions
const showStatusHTML = async (status) => {
  switch (status) {
    case "Draft":
      this.display(["draft_status"]);
      break;
    case "Created":
      this.display(["created_status"]);
      break;
    case "Completed":
      this.display(["completed_status"]);
      break;
    case "Cancelled":
      this.display(["cancelled_status"]);
      break;
    default:
      break;
  }
};

const disabledField = async (status) => {
  if (status === "Completed") {
    this.disabled(
      [
        "packing_status",
        "plant_id",
        "packing_no",
        "gd_id",
        "gd_no",
        "so_id",
        "so_no",
        "customer_id",
        "billing_address",
        "shipping_address",
        "packing_mode",
        "packing_location",
        "assigned_to",
        "created_by",
        "created_at",
        "organization_id",
        "ref_doc",
        "table_hu",
        "table_items",
        "remarks",
      ],
      true,
    );

    this.hide(["button_save_as_draft", "button_created", "button_completed"]);
  } else {
    this.disabled(["ref_doc"], false);
  }
};

const setPlant = async (organizationId) => {
  const deptId = this.getVarSystem("deptIds").split(",")[0];
  let plantId = "";
  const plant = this.getValue("plant_id");

  if (!plant) {
    if (deptId === organizationId) {
      const resPlant = await db
        .collection("blade_dept")
        .where({ parent_id: deptId })
        .get();

      if (!resPlant && resPlant.data.length === 0) {
        plantId = deptId;
      } else {
        plantId = "";
      }
    } else {
      plantId = deptId;
    }
  }

  this.setData({
    organization_id: organizationId,
    ...(!plant ? { plant_id: plantId } : {}),
    created_at: new Date().toISOString().split("T")[0],
  });
};

const viewSerialNumber = async () => {
  const table_items = this.getValue("table_items");
  if (table_items.length > 0) {
    for (const picking of table_items) {
      if (picking.is_serialized_item === 1) {
        await this.display([
          "table_items.select_serial_number",
          "table_items.serial_numbers",
        ]);
      }
    }
  }
};

const setPackingMode = async () => {
  const packingMode = this.getValue("packing_mode");
  if (packingMode === "Basic") {
    this.display(["table_hu.hu_quantity"]);
    this.hide([
      "table_hu.select_items",
      "table_hu.item_count",
      "table_hu.total_quantity",
    ]);
  } else {
    this.hide(["table_hu.hu_quantity"]);
    this.display([
      "table_hu.select_items",
      "table_hu.item_count",
      "table_hu.total_quantity",
    ]);
  }
};

const fetchPickingSetup = async (organizationId) => {
  try {
    const resPickingSetup = await db
      .collection("picking_setup")
      .where({ organization_id: organizationId })
      .get()
      .then((res) => {
        return res.data[0];
      });

    if (!resPickingSetup) {
      console.log("No picking setup found");
      return;
    }

    const pickingAfter = resPickingSetup.picking_after;

    if (pickingAfter === "Sales Order") {
      await this.hide(["gd_id"]);
    }
  } catch (error) {
    console.error(error);
  }
};

const setHUDefaultDocNo = async (organizationID) => {
  const defaultDocFormatFilter = new Filter("all")
    .equal("organization_id", organizationID)
    .equal("document_types", "Handling Unit")
    .numberEqual("is_default", 1)
    .build();
  const resDefaultDocFormat = await db
    .collection("document_number")
    .filter(defaultDocFormatFilter)
    .get();

  if (resDefaultDocFormat && resDefaultDocFormat.data.length > 0) {
    this.setData({
      hu_doc_no_format: resDefaultDocFormat.data[0].id,
    });
  }
};

// Main execution function
(async () => {
  try {
    let pageStatus = "";
    const status = await this.getValue("packing_status");
    console.log("Debug", this.getValues());

    if (this.isAdd) pageStatus = "Add";
    else if (this.isEdit) pageStatus = "Edit";
    else if (this.isView) pageStatus = "View";
    else throw new Error("Invalid page state");

    let organizationId = this.getVarGlobal("deptParentId");
    if (organizationId === "0") {
      organizationId = this.getVarSystem("deptIds").split(",")[0];
    }

    this.setData({ page_status: pageStatus });

    switch (pageStatus) {
      case "Add":
        // Add mode
        this.display(["draft_status"]);
        this.disabled("assigned_to", false);
        this.setData({
          created_by: this.getVarGlobal("nickname"),
        });

        setPlant(organizationId);

        const convertFromGD = this.getValue("plant_id");

        if (convertFromGD) {
          await viewSerialNumber();
        }
        await setPackingMode();
        await fetchPickingSetup(organizationId);
        await setHUDefaultDocNo(organizationId);
        break;

      case "Edit":
        if (status !== "Draft") {
          this.hide(["button_save_as_draft"]);
          await fetchPickingSetup(organizationId);
        }
        await disabledField(status);
        await showStatusHTML(status);
        await viewSerialNumber();
        await setPackingMode();
        await setHUDefaultDocNo(organizationId);
        break;

      case "View":
        await showStatusHTML(status);
        this.hide([
          "button_save_as_draft",
          "button_created",
          "button_completed",
        ]);
        await viewSerialNumber();
        await setPackingMode();
        break;
    }
  } catch (error) {
    console.error(error);
    this.$message.error(error.message || "An error occurred");
  }
})();

setTimeout(async () => {
    if (!this.isAdd) return;
    const maxRetries = 10;
    const interval = 500;
    for (let i = 0; i < maxRetries; i++) {
        const op = await this.onDropdownVisible('packing_no_type', true);
        if (op != null) break;
        await new Promise(resolve => setTimeout(resolve, interval));
    }
    function getDefaultItem(arr) {
        return arr?.find(item => item?.item?.is_default === 1);
    }

    const optionsData = this.getOptionData('packing_no_type') || [];
    const data = getDefaultItem(optionsData);
    if (data) {
        this.setData({ packing_no_type: data.value });
    }
}, 500);

