(async () => {
  const fetchItemData = async (itemId) => {
    const itemData = await db.collection("Item").where({ id: itemId }).get();
    return itemData.data[0];
  };

  const allData = this.getValues();

  const selectedUOM = arguments[0].value;
  const rowIndex = allData.gd_item_balance.row_index;

  console.log("DEBUG - UOM Change:");
  console.log("selectedUOM:", selectedUOM);

  const goodDeliveryUOM = allData.table_gd[rowIndex].gd_order_uom_id;
  const itemId = allData.table_gd[rowIndex].material_id;
  const itemData = await fetchItemData(itemId);
  const tableUOMConversion = itemData.table_uom_conversion;
  const tableItemBalance = allData.gd_item_balance.table_item_balance;

  console.log("goodDeliveryUOM:", goodDeliveryUOM);
  console.log("itemData.based_uom:", itemData.based_uom);
  console.log("tableItemBalance length:", tableItemBalance?.length);
  console.log("tableUOMConversion:", tableUOMConversion);

  const convertBaseToAlt = (baseQty, table_uom_conversion, uom) => {
    if (
      !Array.isArray(table_uom_conversion) ||
      table_uom_conversion.length === 0 ||
      !uom
    ) {
      return baseQty;
    }

    const uomConversion = table_uom_conversion.find(
      (conv) => conv.alt_uom_id === uom
    );

    if (!uomConversion || !uomConversion.alt_qty) {
      return baseQty;
    }

    return Math.round(baseQty * uomConversion.alt_qty * 1000) / 1000;
  };

  const convertQuantityFromTo = (
    value,
    table_uom_conversion,
    fromUOM,
    toUOM,
    baseUOM
  ) => {
    if (!value || fromUOM === toUOM) return value;

    // First convert from current UOM back to base UOM
    let baseQty = value;
    if (fromUOM !== baseUOM) {
      const fromConversion = table_uom_conversion.find(
        (conv) => conv.alt_uom_id === fromUOM
      );
      if (fromConversion && fromConversion.alt_qty) {
        baseQty = value / fromConversion.alt_qty;
      }
    }

    // Then convert from base UOM to target UOM
    return convertBaseToAlt(baseQty, table_uom_conversion, toUOM);
  };

  if (goodDeliveryUOM !== selectedUOM) {
    console.log("UOMs are different, proceeding with conversion...");

    const quantityFields = [
      "block_qty",
      "reserved_qty",
      "unrestricted_qty",
      "qualityinsp_qty",
      "intransit_qty",
      "balance_quantity",
      "gd_quantity",
      "to_quantity", // Include to_quantity for GDPP mode
    ];

    const updatedTableItemBalance = tableItemBalance.map((record, index) => {
      const updatedRecord = { ...record };

      console.log(`Processing record ${index}:`, record);

      quantityFields.forEach((field) => {
        if (updatedRecord[field]) {
          const originalValue = updatedRecord[field];
          updatedRecord[field] = convertQuantityFromTo(
            updatedRecord[field],
            tableUOMConversion,
            goodDeliveryUOM,
            selectedUOM,
            itemData.based_uom
          );
          console.log(`${field}: ${originalValue} -> ${updatedRecord[field]}`);
        }
      });

      return updatedRecord;
    });

    console.log("Final updatedTableItemBalance:", updatedTableItemBalance);

    await this.setData({
      [`gd_item_balance.table_item_balance`]: updatedTableItemBalance,
    });

    this.models["previous_material_uom"] = selectedUOM;

    console.log(
      `Updated table_item_balance quantities from ${goodDeliveryUOM} to ${selectedUOM}`
    );
  } else {
    console.log(
      "UOMs are the same, converting tableItemBalance back to original UOM"
    );

    // Get the previous UOM that the table was converted to
    const previousTableUOM = this.models["previous_material_uom"];

    if (previousTableUOM && previousTableUOM !== goodDeliveryUOM) {
      console.log(
        `Converting table back from ${previousTableUOM} to ${goodDeliveryUOM}`
      );

      const quantityFields = [
        "block_qty",
        "reserved_qty",
        "unrestricted_qty",
        "qualityinsp_qty",
        "intransit_qty",
        "balance_quantity",
        "gd_quantity",
        "to_quantity", // Include to_quantity for GDPP mode
      ];

      const updatedTableItemBalance = tableItemBalance.map((record, index) => {
        const updatedRecord = { ...record };

        console.log(`Processing record ${index}:`, record);

        quantityFields.forEach((field) => {
          if (updatedRecord[field]) {
            const originalValue = updatedRecord[field];
            updatedRecord[field] = convertQuantityFromTo(
              updatedRecord[field],
              tableUOMConversion,
              previousTableUOM,
              goodDeliveryUOM,
              itemData.based_uom
            );
            console.log(
              `${field}: ${originalValue} -> ${updatedRecord[field]}`
            );
          }
        });

        return updatedRecord;
      });

      console.log("Final updatedTableItemBalance:", updatedTableItemBalance);

      await this.setData({
        [`gd_item_balance.table_item_balance`]: updatedTableItemBalance,
        [`gd_item_balance.previous_material_uom`]: goodDeliveryUOM,
      });

      console.log(
        `Converted table_item_balance back from ${previousTableUOM} to ${goodDeliveryUOM}`
      );
    } else {
      console.log("Table is already in correct UOM, no conversion needed");
    }
  }
})();

(async () => {
  try {
    console.log("Triggering storage location");

    const storageLocationId = arguments[0]?.value;
    const previousStorageLocationId = this.models["previous_storage_location_id"];
    const currentTableData = this.getValues()?.gd_item_balance?.table_item_balance || [];
    let storageLocationData = this.models["default_storage_location"];

    console.log("storageLocationId", storageLocationId);
    console.log("previousStorageLocationId", previousStorageLocationId);

    if (storageLocationId === previousStorageLocationId) {
      console.log("Storage location unchanged, skipping confirmation");
      this.models["previous_storage_location_id"] = storageLocationId;
      return;
    }

    if (!storageLocationData && storageLocationData.length === 0) {
      storageLocationData = await db
        .collection("storage_location")
        .where({ id: storageLocationId })
        .get()
        .then((res) => res.data[0]);
    }

    const fullBalanceData = this.models["full_balance_data"];

    const hasAllocatedItems = currentTableData.some(
      (data) => (data.gd_quantity || 0) > 0
    );

    if (hasAllocatedItems && previousStorageLocationId) {
      try {
        await this.$confirm(
          "There are items with allocated quantities. Changing storage location will reset all allocated quantities. Do you want to continue?",
          "Warning",
          {
            confirmButtonText: "OK",
            cancelButtonText: "Cancel",
            type: "warning",
          }
        );

        fullBalanceData.forEach((data) => {
          data.gd_quantity = 0;
        });

        console.log("User confirmed: Reset all gd_quantity to 0");
      } catch {
        console.log("User cancelled: Restoring previous storage location");
        await this.setData({
          "gd_item_balance.storage_location": previousStorageLocationId,
          "gd_item_balance.table_item_balance": currentTableData,
        });
        return;
      }
    }

    this.models["previous_storage_location_id"] = storageLocationId;

    const binLocationList =
      storageLocationData.table_bin_location?.map(
        (bin) => bin.bin_location_id
      ) || [];

    const filteredBalanceData =
      fullBalanceData?.filter((data) => {
        const hasAllocation = (data.gd_quantity || 0) > 0;
        const inStorageLocation = binLocationList.includes(data.location_id);

        return hasAllocation || inStorageLocation;
      }) || [];

    if (
      !storageLocationId ||
      !storageLocationData ||
      !fullBalanceData ||
      storageLocationId === "" ||
      filteredBalanceData.length === 0
    ) {
      console.log("No storage location data found");
      if (filteredBalanceData.length === 0) {
        this.$message.error(
          "Inventory is not available in this storage location"
        );
      }
      await this.setData({
        "gd_item_balance.table_item_balance": fullBalanceData,
        "gd_item_balance.storage_location": "",
      });
      return;
    }

    await this.setData({
      "gd_item_balance.table_item_balance": filteredBalanceData,
    });
  } catch (error) {
    console.error("Error in storage location dialog:", error);
  }
})();

